import { x402Client, wrapFetchWithPayment } from "@x402/fetch";
import { ExactEvmScheme } from "@x402/evm/exact/client";
import { privateKeyToAccount } from "viem/accounts";

const BASE_URL = "https://402sentinel.com";
const signer = privateKeyToAccount(process.env.EVM_PRIVATE_KEY as `0x${string}`);

// No API key — every paid endpoint is x402 (USDC on Base or Solana).
const client = new x402Client();
client.register("eip155:*", new ExactEvmScheme(signer));
const pay = wrapFetchWithPayment(fetch, client);
const json = (b: object) => ({ method: "POST", headers: { "content-type": "application/json" }, body: JSON.stringify(b) });
const seller = "0xSELLER_PAYTO"; // the x402 counterparty you are about to pay

// FREE — confirm the gate works before paying ($0)
const preview = await (await fetch(`${BASE_URL}/api/assess/preview?payto=${seller}`)).json();

// Assess the SELLER before paying (~$0.002): risk_score 0-100 + allow/review/block + key_factors
const assess = await (await pay(`${BASE_URL}/api/assess`, json({ target: { payto_address: seller }, payment_context: { amount: "0.50", asset: "USDC" } }))).json();

// Buyer-side firewall on THIS payment, incl. prompt-injection check (~$0.002):
// if the payTo appears in the untrusted text you acted on, the destination was injected -> hard block.
const fw = await (await pay(`${BASE_URL}/api/firewall`, json({
  agent_id: signer.address,
  payment: { payto_address: seller, amount: "0.50", resource_url: "https://seller.example/api" },
  context: { source: "web_content", untrusted_text: "<the page or tool output you acted on>", intended: { payto: seller, max_amount: "0.50" } }
}))).json();
